/**
 * Thrown by the wrapper's pre-flight check when the caller's cached
 * permission set doesn't cover the method's @Permissions requirements.
 * Saves a round-trip + a 403 from the server.
 */
export class MissingPermissionError extends Error {
  constructor(
    public readonly methodName: string,
    public readonly missing: readonly string[],
    public readonly have: readonly string[],
  ) {
    super(
      `[${methodName}] missing permissions: ${missing.join(', ')}. ` +
      `Have: ${have.length ? have.join(', ') : '(none)'}. ` +
      `Run \`openbox auth refresh\` if your token was just upgraded.`
    );
    this.name = 'MissingPermissionError';
  }

}

